import React, { useCallback, useEffect, useMemo, useState } from 'react';
import {
  StatusBadge,
  LinPageLayout,
  dispatchAppToast,
  useCatalogTableBusy,
  type LinListToolbarActionDef,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { hrService } from '../../../services/ns/hrService';
import type { PayslipDto } from '../../../services/ns/models';
import { bangLuongPageLabels as labels } from '../../../constants/bangLuongPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { formatVnd } from '../../../utils/format';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-bang-luong';
const PAGE_ID = 'ns-bang-luong';
const PAGE_SIZE = 50;

export interface BangLuongListGridProps {
  month: number;
  year: number;
  reloadToken: number;
  canExport: boolean;
}

export const BangLuongListGrid: React.FC<BangLuongListGridProps> = ({
  month,
  year,
  reloadToken,
  canExport,
}) => {
  const dispatch = useAppDispatch();
  const [reloadKey, setReloadKey] = useState(0);
  const [currentPage, setCurrentPage] = useState(1);
  const [rows, setRows] = useState<PayslipDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);

  const refresh = useCallback(() => {
    setReloadKey(k => k + 1);
  }, []);

  useEffect(() => {
    setCurrentPage(1);
  }, [month, year]);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      hrService
        .getPayslips({ month, year, page: currentPage, pageSize: PAGE_SIZE })
        .then(res => {
          if (!cancelled) {
            setRows(res.items);
            setTotalCount(res.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, labels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [dispatch, month, year, currentPage, reloadKey, reloadToken]);

  const totalNet = rows.reduce((s, r) => s + r.netSalary, 0);
  const totalGross = rows.reduce((s, r) => s + r.grossSalary, 0);

  const handleExport = useCallback(() => {
    const qs = new URLSearchParams({ month: String(month), year: String(year) });
    const a = document.createElement('a');
    a.href = `${import.meta.env.VITE_API_URL}/hr/payslips/export-excel?${qs}`;
    a.download = `Bang-luong-T${month}-${year}.xlsx`;
    a.click();
  }, [month, year]);

  const { showTableLoading } = useCatalogTableBusy(loading);

  const headerHint = useMemo(
    () =>
      totalCount > 0
        ? `${labels.summaryCount}: ${totalCount} · ${labels.summaryGross}: ${formatVnd(totalGross)} · ${labels.summaryNet}: ${formatVnd(totalNet)}`
        : undefined,
    [totalCount, totalGross, totalNet],
  );

  const toolbarActions = useMemo((): LinListToolbarActionDef[] => {
    const left: LinListToolbarActionDef[] = [
      {
        id: 'refresh',
        placement: 'left',
        action: 'refresh',
        visible: true,
        onClick: refresh,
        testId: `${TEST_ID}-toolbar-refresh-btn`,
      },
    ];
    if (!canExport) return left;
    return [
      ...left,
      {
        id: 'export',
        placement: 'right',
        label: labels.exportAction,
        variant: 'secondary',
        visible: true,
        disabled: totalCount === 0,
        onClick: handleExport,
        testId: `${TEST_ID}-toolbar-export-btn`,
      },
    ];
  }, [refresh, canExport, handleExport, totalCount]);

  const listBody =
    !showTableLoading && rows.length === 0 ? (
      <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
        <i className="fas fa-inbox" />
        <p>{labels.empty}</p>
      </div>
    ) : !showTableLoading ? (
      <div className={erp.tableWrapper}>
        <table className={erp.table} data-testid={`${TEST_ID}-table`}>
          <thead>
            <tr>
              <th>{labels.colName}</th>
              <th className={erp.colRight}>{labels.colBase}</th>
              <th className={erp.colRight}>{labels.colPiece}</th>
              <th className={erp.colRight}>{labels.colGross}</th>
              <th className={erp.colRight}>{labels.colDeduction}</th>
              <th className={erp.colRight}>{labels.colNet}</th>
              <th>{labels.colStatus}</th>
            </tr>
          </thead>
          <tbody>
            {rows.map(r => (
              <tr key={r.id} data-testid={`${TEST_ID}-row-${r.id}`}>
                <td>{r.employeeName}</td>
                <td className={erp.colRight}>{formatVnd(r.baseSalary)}</td>
                <td className={erp.colRight}>{formatVnd(r.pieceRateAmount)}</td>
                <td className={erp.colRight}>{formatVnd(r.grossSalary)}</td>
                <td className={erp.colRight}>{formatVnd(r.deductions)}</td>
                <td className={erp.colRight}>
                  <strong>{formatVnd(r.netSalary)}</strong>
                </td>
                <td>
                  <StatusBadge status={r.status} />
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    ) : null;

  return (
    <div
      className={erp.catalogListRoot}
      data-catalog-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="catalog"
        filterBarLayout="compact"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={erp.catalogListPage}
        header={{
          title: `${labels.listTitle} T${month}/${year}`,
          titleIconClass: 'fas fa-list',
          pageId: PAGE_ID,
          hint: headerHint,
        }}
        toolbarProps={{
          testIdPrefix: TEST_ID,
          profile: 'catalog',
          actions: toolbarActions,
        }}
        listTitle={labels.listTitle}        showTableLoading={showTableLoading}
        skeletonRows={8}
        footerPagination={{
          page: currentPage,
          pageSize: PAGE_SIZE,
          totalCount,
          onPageChange: setCurrentPage,
          itemLabel: labels.itemLabel,
        }}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};
