import React, { useCallback, useState } from 'react';
import { HrPeriodActionPanel } from '../../../components/ns/HrPeriodActionPanel';
import { BangLuongListGrid } from './BangLuongListGrid';
import { hrService } from '../../../services/ns/hrService';
import { bangLuongPageLabels as labels } from '../../../constants/bangLuongPageLabels';
import { useHrPayrollPermissions } from '../../../hooks/useHrPermissions';

const BangLuongPage: React.FC = () => {
  const { canRead, canRun, canPost } = useHrPayrollPermissions();
  const [reloadToken, setReloadToken] = useState(0);

  const bumpReload = useCallback(() => {
    setReloadToken(t => t + 1);
  }, []);

  const getStatus = useCallback(async (month: number, year: number) => {
    const res = await hrService.getPayslips({ month, year, pageSize: 1 });
    if (res.totalCount === 0) return 'Chưa có phiếu lương';
    return `${res.totalCount} phiếu lương · T${month}/${year}`;
  }, []);

  return (
    <HrPeriodActionPanel
      testIdPrefix="ns-bang-luong"
      title={labels.title}
      icon="fa-money-check-alt"
      description={labels.description}
      periodSectionTitle={labels.periodSection}
      runLabel={labels.runLabel}
      postLabel={labels.postLabel}
      getStatus={getStatus}
      onRun={(m, y) => hrService.calculatePayroll(m, y)}
      onPost={(m, y) => hrService.confirmPayroll(m, y)}
      onActionComplete={bumpReload}
      runPermitted={canRun}
      postPermitted={canPost}
      renderExtra={({ month, year }) => (
        <BangLuongListGrid
          month={month}
          year={year}
          reloadToken={reloadToken}
          canExport={canRead}
        />
      )}
    />
  );
};

export default BangLuongPage;
